ts=[],settings={},suppliers=[],purchases=[],cashbook=[],stockHistory=[],filter='all',editId=null,discType='pct',modalPayments=[],editSupplierId=null,st,curMode='dark',curColor='mavi';// THEMEfunction applyTheme(mode,color){curMode=mode;curColor=color;document.documentElement.setAttribute('data-theme',mode);const c=COLORS[color];if(!c)return;const vals=mode==='dark'?c.dark:c.light;const r=document.documentElement.style;r.setProperty('--accent',vals.accent);r.setProperty('--accent2',vals.accent2);r.setProperty('--accent-hover',vals.accent);r.setProperty('--accent-dim',vals.adim);document.querySelectorAll('.theme-card').forEach(x=>x.classList.toggle('active',x.dataset.color===color));document.getElementById('modeDark').classList.toggle('active',mode==='dark');document.getElementById('modeLight').classList.toggle('active',mode==='light');}function setMode(mode){applyTheme(mode,curColor);saveTheme();}async function saveTheme(){try{await upsertSetting('theme_mode',curMode);await upsertSetting('theme_color',curColor);}catch(e){}}function renderThemes(){document.getElementById('themeGrid').innerHTML=Object.entries(COLORS).map(([k,c])=>'<div class="theme-card'+(curColor===k?' active':'')+'" data-color="'+k+'" onclick="selectColor(\''+k+'\')"><div class="theme-preview" style="background:'+c.p+'"><\/div><div class="theme-name">'+c.name+'<\/div><\/div>').join('');}function selectColor(k){applyTheme(curMode,k);renderThemes();saveTheme();}async function saveBizName(){const n=document.getElementById('setBizName').value.trim()||'Torf ve Toprak';const s=document.getElementById('setBizSub').value.trim()||'Satis ve Stok Takibi';document.getElementById('bizName').textContent=n;document.getElementById('bizSub').textContent=s;sync('','Kaydediliyor...');try{await upsertSetting('biz_name',n);await upsertSetting('biz_sub',s);sync('ok','Kaydedildi');}catch(e){sync('err','Hata');}}async function upsertSetting(key,value){try{await sb('settings','POST',[{key,value}],'');}catch(e){await sb('sett